# Description #

Added a rough working version to decode ACL for keychain items. 

# Known Issues #

Needs some tidying up, especially in how the access_control is formatted, but thought I would open merge thread before we start duplicating work. 

# Example Output #

```
ubuntu@ubuntu-dev:~/workspace/objection$ python3 -m objection.console.cli --gadget Keychain explore

     _     _         _   _
 ___| |_  |_|___ ___| |_|_|___ ___
| . | . | | | -_|  _|  _| | . |   |
|___|___|_| |___|___|_| |_|___|_|_|
        |___|(object)inject(ion) v1.0.3

     Runtime Mobile Exploration
        by: @leonjza from @sensepost

[tab] for command suggestions
macos’s iPhone on (iPhone: 10.1.1) [usb] # ios keychain dump
Reading the keychain...
Get all of the attributes by adding `--json keychain.json` to this command

Class                     Account    Service    Generic    Access Control                          Data
------------------------  ---------  ---------  ---------  --------------------------------------  ------
kSecClassGenericPassword  test1      tests                                                         test1
kSecClassGenericPassword  test2      tests                                                         test2
kSecClassGenericPassword  test3      tests                 TouchIDAny                              test3
kSecClassGenericPassword  test4      tests                 TouchIDCurrentSet                       test4
kSecClassGenericPassword  test5      tests                 UserPresence                            test5
kSecClassGenericPassword  test6      tests                 DevicePasscode                          test6
kSecClassGenericPassword  test7      tests                 DevicePasscode  And  TouchIDCurrentSet  test7
```

# Test Code # 

```

#import "ViewController.h"

@interface ViewController ()

@end

@implementation ViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    // Do any additional setup after loading the view, typically from a nib.
}


- (void)didReceiveMemoryWarning {
    [super didReceiveMemoryWarning];
    // Dispose of any resources that can be recreated.
}

- (IBAction)onButtonPress:(id)sender {
    
}

- (void)testKeyChain()    {
    [self addKeyChainItemAccessibleFirstUnlock];
    [self addKeyChainItemAccessibleWhenUnlockedThisDeviceOnly];
    [self addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyTouchIDAny];
    [self addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyTouchIDCurrentSet];
    [self addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyUserPresence];
    [self addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyDevicePasscode];
    [self addKeyChainItemAccessibleWhenUnlockedTouchIDAnyOrDev];
}

- (void)addKeyChainItemAccessibleFirstUnlock{
    NSData *secret = [@"test1" dataUsingEncoding:NSUTF8StringEncoding];
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test1",
                            (id)kSecAttrAccessible: (id) kSecAttrAccessibleAfterFirstUnlock,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}

- (void)addKeyChainItemAccessibleWhenUnlockedThisDeviceOnly{
    NSData *secret = [@"test2" dataUsingEncoding:NSUTF8StringEncoding];
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test2",
                            (id)kSecAttrAccessible: (id) kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}


- (void)addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyTouchIDAny{
    
    
    NSData *secret = [@"test3" dataUsingEncoding:NSUTF8StringEncoding];
    
    SecAccessControlRef access = SecAccessControlCreateWithFlags(kCFAllocatorDefault, kSecAttrAccessibleWhenUnlocked, kSecAccessControlTouchIDAny, NULL);
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test3",
                            (id)kSecAttrAccessControl: (__bridge_transfer id)access,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}


- (void)addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyTouchIDCurrentSet{
    
    
    NSData *secret = [@"test4" dataUsingEncoding:NSUTF8StringEncoding];
    
    SecAccessControlRef access = SecAccessControlCreateWithFlags(kCFAllocatorDefault, kSecAttrAccessibleWhenUnlocked, kSecAccessControlTouchIDCurrentSet, NULL);
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test4",
                            (id)kSecAttrAccessControl: (__bridge_transfer id)access,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}

- (void)addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyUserPresence{
    
    
    NSData *secret = [@"test5" dataUsingEncoding:NSUTF8StringEncoding];
    
    SecAccessControlRef access = SecAccessControlCreateWithFlags(kCFAllocatorDefault, kSecAttrAccessibleWhenUnlocked, kSecAccessControlUserPresence, NULL);
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test5",
                            (id)kSecAttrAccessControl: (__bridge_transfer id)access,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}

- (void)addKeyChainItemAccessibleWhenUnlockedThisDeviceOnlyDevicePasscode{
    
    
    NSData *secret = [@"test6" dataUsingEncoding:NSUTF8StringEncoding];
    
    SecAccessControlRef access = SecAccessControlCreateWithFlags(kCFAllocatorDefault, kSecAttrAccessibleWhenUnlocked, kSecAccessControlDevicePasscode, NULL);
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test6",
                            (id)kSecAttrAccessControl: (__bridge_transfer id)access,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}

- (void)addKeyChainItemAccessibleWhenUnlockedTouchIDAnyOrDev{
    
    
    NSData *secret = [@"test7" dataUsingEncoding:NSUTF8StringEncoding];
    
    SecAccessControlRef access = SecAccessControlCreateWithFlags(kCFAllocatorDefault, kSecAttrAccessibleWhenUnlocked, kSecAccessControlDevicePasscode | kSecAccessControlAnd |  kSecAccessControlTouchIDCurrentSet, NULL);
    
    NSDictionary *query = @{
                            (id)kSecClass: (id)kSecClassGenericPassword,
                            (id)kSecAttrService: @"tests",
                            (id)kSecAttrAccount: @"test7",
                            (id)kSecAttrAccessControl: (__bridge_transfer id)access,
                            (id)kSecValueData: secret,
                            };
    
    SecItemAdd((CFDictionaryRef)query, NULL);
}
@end

```

